---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  size?: "default" | "sm" | "lg"
}

const { class: className, size = "default", ...props } = Astro.props
---

<div
  data-slot="avatar"
  data-size={size}
  class={cn(
    "after:border-border group/avatar relative flex size-8 shrink-0 overflow-hidden rounded-full select-none after:absolute after:inset-0 after:rounded-full after:border after:mix-blend-darken data-[size=lg]:size-10 data-[size=sm]:size-6 dark:after:mix-blend-lighten",
    className
  )}
  {...props}
>
  <slot />
</div>

---
import { Image } from "astro:assets"
import type { ComponentProps } from "astro/types"

import { cn } from "@/lib/utils"

type Props = Partial<ComponentProps<typeof Image>>

const {
  class: className,
  alt = "",
  width = 44,
  height = 44,
  sizes = "44px",
  widths = [44, 88, 176],
  ...props
} = Astro.props
---

{
  props.src && (
    <Image
      data-slot="avatar-image"
      class={cn(
        "absolute inset-0 z-10 aspect-square size-full rounded-full object-cover",
        className
      )}
      alt={alt}
      width={width}
      height={height}
      sizes={sizes}
      widths={widths}
      {...(props as any)}
    />
  )
}
